INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ca3bf741-2aec-461c-9c30-6a59961deb6f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Terraform's Core Loop — Providers, Resources, State, and Plan/Apply$escape$,
  $escape$Terraform's execution model revolves around four primitives working in sequence. Providers are plugins that translate your HCL into API calls — `hashicorp/aws` v5 speaks AWS APIs, `hashicorp/azurerm` speaks Azure. Declare them in a `required_providers` block with pinned versions to avoid drift. Resources are the actual infrastructure objects: each `resource` block maps to a single API-managed entity, with a type (`aws_s3_bucket`) and a local name used for cross-references via expressions like `aws_s3_bucket.logs.id`.

State is Terraform's source of truth — a JSON snapshot in `terraform.tfstate` mapping your config to real-world resource IDs. Remote backends (S3 + DynamoDB for AWS, Azure Blob for Azure) enable team use and state locking. Never edit state manually; use `terraform state mv` or `terraform import` instead.

The plan/apply lifecycle is deterministic: `terraform init` downloads providers, `terraform plan` diffs desired vs. current state and emits a changeset, `terraform apply` executes it. Passing `-target=aws_instance.web` scopes apply to one resource — useful for debugging, but avoid it in CI pipelines as it can leave state partially applied.$escape$,
  $escape$terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
  backend "s3" {
    bucket         = "my-tf-state"
    key            = "prod/terraform.tfstate"
    region         = "us-east-1"
    dynamodb_table = "tf-state-lock"
  }
}

provider "aws" { region = "us-east-1" }

resource "aws_s3_bucket" "logs" {
  bucket = "my-app-logs-2024"
}

output "bucket_arn" {
  value = aws_s3_bucket.logs.arn
}$escape$,
