INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f7889b03-55a3-4137-bf6f-cd9980974056',
  '00000000-0000-0000-0000-000000000001',
  $escape$Terraform Modules — Registry, Versioning, and Reuse Done Right$escape$,
  $escape$Terraform modules are the primary unit of reuse: a directory with `.tf` files that accepts input variables and returns outputs. You can source them from the public Terraform Registry, private registries (Terraform Cloud/Enterprise), Git repos, or local paths. Registry modules follow a strict `<NAMESPACE>/<MODULE>/<PROVIDER>` naming convention and support semantic versioning via the `version` argument — something Git sources don't enforce natively.

Always pin registry modules to a specific minor version range like `~> 1.4` to allow patch updates while guarding against breaking changes. For internal modules, use a private registry or a dedicated Git tag strategy (`ref=v1.4.0`) — never point to a branch in production, as the ref is mutable. Structure monorepos with a `modules/` directory for reusable components and a `live/` or `envs/` directory for root modules that compose them. Pass outputs between modules using `module.<name>.<output>` references. Use `terraform get -update` to pull the latest pinned version after bumping the constraint.$escape$,
  $escape$module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 5.1"

  name            = "prod-vpc"
  cidr            = "10.0.0.0/16"
  azs             = ["us-east-1a", "us-east-1b"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24"]
  public_subnets  = ["10.0.101.0/24", "10.0.102.0/24"]

  enable_nat_gateway = true
}

output "vpc_id" {
  value = module.vpc.vpc_id
}$escape$,
  $escape$bash$escape$,
