INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b2d5dbd9-3fdb-472c-b93a-57314be07d38',
  '00000000-0000-0000-0000-000000000001',
  $escape$Terraform vs Pulumi — Real Languages, Type Safety, and Actual Unit Tests$escape$,
  $escape$Terraform's HCL is purpose-built but hits a ceiling fast: no real loops without count/for_each hacks, no unit tests without Terratest spinning up real infra, and type errors surface only at plan/apply time. Pulumi replaces HCL with TypeScript, Python, or Go — the same languages you already test and lint. Your S3 bucket isn't a resource block, it's a typed object; passing a wrong argument is a compile error, not a failed apply 3 minutes in. Where Terraform forces you to work around dynamic blocks and locals for conditional logic, Pulumi lets you use native if/for. Testing is the real unlock: Pulumi's SDK ships a mock provider, so you can unit-test your stack logic without touching AWS at all — no state files, no credentials, no cleanup. You still get a state backend (Pulumi Cloud or S3-compatible), drift detection, and policy-as-code via CrossGuard. The migration path is incremental: pulumi convert --from terraform ingests your existing .tf files and outputs equivalent Pulumi TypeScript, letting you migrate module by module rather than all at once.$escape$,
  $escape$import * as aws from "@pulumi/aws";
import { interpolate } from "@pulumi/pulumi";

// Type-safe: wrong arg here = compile error, not failed apply
const bucket = new aws.s3.BucketV2("assets", {
  tags: { Environment: "prod" },
});

// Native language logic — no count/for_each workaround
const envs = ["prod", "staging"];
const queues = envs.map(env =>
  new aws.sqs.Queue(`queue-${env}`, { visibilityTimeoutSeconds: 30 })
);

export const bucketArn = bucket.arn;$escape$,
  $escape$typescript$escape$,
