INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'dd3d197f-85bc-4f52-83a4-63e09d89e167',
  '00000000-0000-0000-0000-000000000001',
  $escape$Terraform Linting & Formatting — tflint, terraform fmt, and Enforcing Consistent Style$escape$,
  $escape$terraform fmt is non-negotiable in any Terraform workflow — it enforces canonical HCL formatting (2-space indents, aligned equals signs, sorted blocks) and is fully deterministic. Run it with -recursive to catch all .tf files in subdirectories. But fmt only handles style; it won't catch logic errors. That's where tflint comes in. tflint is a pluggable linter that catches provider-specific mistakes — like invalid aws_instance.instance_type values or deprecated argument usage — errors that terraform validate misses entirely. Install the AWS ruleset with tflint --init using a .tflint.hcl config file that declares the plugin. In CI, run fmt -check (exits non-zero without modifying files) before tflint, so formatting failures fail fast without masking lint output. Pair this with a pre-commit hook using the terraform-pre-commit hooks library to block unformatted or unlinted code at commit time. Together, these tools eliminate entire classes of plan-time surprises and keep multi-author modules readable without style debates.$escape$,
  $escape$# .tflint.hcl
plugin "aws" {
  enabled = true
  version = "0.32.0"
  source  = "github.com/terraform-linters/tflint-ruleset-aws"
}

rule "terraform_required_version" {
  enabled = true
}

# CI pipeline step (bash)
terraform fmt -check -recursive . && \
  tflint --init && \
  tflint --recursive$escape$,
  $escape$bash$escape$,
