INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'efcf673f-2374-43b3-a7cd-4c3c69fb6693',
  '00000000-0000-0000-0000-000000000001',
  $escape$Terraform vs Pulumi vs Bicep vs CDK — A Terraform User's Decision Framework$escape$,
  $escape$Terraform's state model and provider registry (3,700+ providers) make it the default for multi-cloud orgs — but the right tool depends on real constraints.

**Pick Terraform when:** You need multi-cloud in a single plan (`aws` + `azurerm` + `google` providers in one root module), your team lives in HCL, or you need Sentinel policy-as-code and drift detection via `terraform plan -refresh-only`. The `moved` block (1.1+) and `import` block (1.5+) let you refactor state without destroying resources — a migration superpower.

**Pick Pulumi when:** HCL's limited expressiveness blocks you — no first-class functions, no native unit testing. Pulumi's `Output<T>` and real language loops replace fragile `count`/`for_each` workarounds.

**Pick Bicep when:** You're Azure-only and want ARM's full API surface without JSON verbosity. No state file — Azure IS the state.

**Pick CDK when:** You're AWS-only and want L2/L3 constructs. Understand that it's CloudFormation underneath — you inherit the 200-resource stack limit and rollback behavior.

**The trap:** Never choose CDK or Bicep for multi-cloud. Never choose Terraform if your team won't write HCL — tool friction kills consistency faster than wrong syntax.$escape$,
  $escape$# Terraform 1.5+ import block — killer feature when migrating FROM Bicep/CDK
# Generates config AND wires state without destroy/recreate

import {
  to = aws_s3_bucket.app_assets
  id = "my-app-assets-prod"
}

import {
  to = azurerm_resource_group.shared
  id = "/subscriptions/abc-123/resourceGroups/shared-rg"
}

# Multi-cloud in a single plan — structurally impossible in Bicep or CDK
resource "aws_s3_bucket" "app_assets" {
  bucket = "my-app-assets-prod"
}

resource "azurerm_resource_group" "shared" {
  name     = "shared-rg"
  location = "eastus"
}$escape$,
